     2→import { instanceToPlain, plainToInstance } from 'class-transformer';
     3→import { validate, ValidationError } from 'class-validator';
     4→import { Knex } from 'knex';
     5→import { InjectConnection } from 'nest-knexjs';
     6→
     7→import { BaseRootCategoryCorrelationDto } from '@modules/db/root-categories-correlations/dto/root-category-correlation.base.dto';
