    10→import {
    11→	KNEX_READ_CONNECTION,
    12→	TABLE_NAME_ROOT_CATEGORIES_CORRELATIONS,
    13→} from '@constants/db.constant';
    14→
    15→@Injectable()
    16→export class RootCategoryCorrelationModel {
    17→	private readonly logger = new Logger(RootCategoryCorrelationModel.name);
    18→	private readonly tableName = TABLE_NAME_ROOT_CATEGORIES_CORRELATIONS;
    19→
    20→	constructor(@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex) {}
    21→
    22→	async findTopCorrelatedCategories({
    23→		rootCategoryId,
    24→		limit = 4,
    25→		exclude = [],
    26→	}: {
    27→		rootCategoryId: IRootCategoryCorrelationBase['root_category_id'];
    28→		limit?: number;
    29→		exclude?: number[];
    30→	}): Promise<IRootCategoryCorrelationBase[]> {
    31→		try {
    32→			const results = await this.knexRead<BaseRootCategoryCorrelationDto>(this.tableName)
    33→				.where({ root_category_id: rootCategoryId })
    34→				.whereNotIn('edge_id', exclude)
    35→				.whereNull('deleted_at')
    36→				.orderBy('edge_weight', 'desc')
    37→				.limit(limit);
    38→
    39→			this.logger.debug(
    40→				`Found ${results.length} correlated root categories for category ${rootCategoryId}`,
    41→			);
    42→
    43→			const validatedResults = await Promise.all(
    44→				results.map(async (result) => {
    45→					const dto = plainToInstance(BaseRootCategoryCorrelationDto, result);
    46→					const errors = await validate(dto);
    47→					if (errors.length > 0) {
    48→						this.logger.error(
    49→							`Validation failed for root category correlation data: ${this.formatValidationErrors(errors)}`,
    50→						);
    51→						throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
    52→					}
    53→					return instanceToPlain<BaseRootCategoryCorrelationDto>(
    54→						result,
    55→					) as IRootCategoryCorrelationBase;
    56→				}),
    57→			);
    58→
    59→			return validatedResults;
    60→		} catch (error) {
    61→			this.logger.error(
    62→				`Failed to find correlated root categories for category ${rootCategoryId}: ${(error as Error).message}`,
    63→			);
    64→			throw error;
    65→		}
    66→	}
    67→
    68→	private formatValidationErrors(errors: ValidationError[]): string {
    69→		return errors
    70→			.map(
    71→				(error) =>
    72→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
    73→			)
    74→			.join('; ');
    75→	}
    76→}
