import { Injectable, Logger } from '@nestjs/common';
import { instanceToPlain, plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { BaseRootCategoryCorrelationDto } from '@modules/db/root-categories-correlations/dto/root-category-correlation.base.dto';
import { IRootCategoryCorrelationBase } from '@modules/db/root-categories-correlations/types/root-category-correlation.base.interface';

import {
	KNEX_READ_CONNECTION,
	TABLE_NAME_ROOT_CATEGORIES_CORRELATIONS,
} from '@constants/db.constant';

@Injectable()
export class RootCategoryCorrelationModel {
	private readonly logger = new Logger(RootCategoryCorrelationModel.name);
	private readonly tableName = TABLE_NAME_ROOT_CATEGORIES_CORRELATIONS;

	constructor(@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex) {}

	async findTopCorrelatedCategories({
		rootCategoryId,
		limit = 4,
		exclude = [],
	}: {
		rootCategoryId: IRootCategoryCorrelationBase['root_category_id'];
		limit?: number;
		exclude?: number[];
	}): Promise<IRootCategoryCorrelationBase[]> {
		try {
			const results = await this.knexRead<BaseRootCategoryCorrelationDto>(this.tableName)
				.where({ root_category_id: rootCategoryId })
				.whereNotIn('edge_id', exclude)
				.whereNull('deleted_at')
				.orderBy('edge_weight', 'desc')
				.limit(limit);

			this.logger.debug(
				`Found ${results.length} correlated root categories for category ${rootCategoryId}`,
			);

			const validatedResults = await Promise.all(
				results.map(async (result) => {
					const dto = plainToInstance(BaseRootCategoryCorrelationDto, result);
					const errors = await validate(dto);
					if (errors.length > 0) {
						this.logger.error(
							`Validation failed for root category correlation data: ${this.formatValidationErrors({ errors })}`,
						);
						throw new Error(
							`Validation failed: ${this.formatValidationErrors({ errors })}`,
						);
					}
					return instanceToPlain<BaseRootCategoryCorrelationDto>(
						result,
					) as IRootCategoryCorrelationBase;
				}),
			);

			return validatedResults;
		} catch (error) {
			this.logger.error(
				`Failed to find correlated root categories for category ${rootCategoryId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
		return errors
			.map(
				(error) =>
					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
			)
			.join('; ');
	}
}

