   136→			this.logger.debug('[getRelatedProducts] Algolia returned related IDs', {
   137→				count: styleIds.length,
   138→			});
   139→
   140→			if (styleIds.length === 0) {
   141→				throw new NotFoundException(
   142→					`No related products found for product ID: ${productId}`,
   143→				);
   144→			}
   145→
   146→			const [currentStyleColor, { products, mvRecords }] = await Promise.all([
   147→				this.getCurrentColorStyle(numericProductId, colorId),
   148→				this.productHydrationService.hydrateProductsWithColors({
   149→					styleIds,
   150→				}),
   151→			]);
   152→
   153→			const relatedProducts = currentStyleColor
   154→				? await this.applyColorMatching(products, mvRecords, currentStyleColor)
   155→				: products;
   156→			this.logger.debug('[getRelatedProducts] Hydration complete', {
   157→				hydratedCount: relatedProducts.length,
   158→			});
