   169→				color_id: colorId ?? null,
   170→			};
   171→		} catch (error: unknown) {
   172→			const err = error instanceof Error ? error : new Error(String(error));
   173→			this.logger.error(
   174→				`Error fetching related products from Algolia for productId ${productId}, colorId ${colorId}: ${err.message}`,
   175→				err.stack,
   176→			);
   177→
   178→			await this.metricsService.incrementDailyCounter({
   179→				metricType: dailyTrackingKeys.MMS_REQUESTS,
   180→			});
   181→
   182→			const [alternativeStyleIds, currentStyleColor] = await Promise.all([
   183→				this.styleAlternativesService.getAlternativeStyleIds({
   184→					styleId: numericProductId,
   185→				}),
   186→				this.getCurrentColorStyle(numericProductId, colorId),
