	describe('GET /related-products/:productId - Fallback Without Limit', () => {
		it('should use alternatives.length when limit is not provided in fallback', async () => {
			const testProductId = '12345';

			jest.spyOn(cacheService, 'get').mockImplementation(() => Promise.resolve(null));
			jest.spyOn(algoliaService, 'getRelatedProductIds').mockResolvedValue([]);

			jest
				.spyOn(styleAlternativesService, 'getAlternativeStyleIds')
				.mockResolvedValue([885600, 885601, 885602]);

			jest
				.spyOn(productHydrationService, 'hydrateProducts')
				.mockResolvedValue(mockMmsRelatedProducts);

			const response = await request(getHttpServer)
				.get(`/related-products/${testProductId}`)
				.expect(200);

			const body = response.body as RelatedProductsResponseDto;

