	describe('branch coverage for service and controller edge cases', () => {
		it('should cover responseFormatter null-coalescing branch for brand_products', async () => {
			jest.spyOn(productHydrationService, 'getProductsByBrands').mockResolvedValue({
				products: mockBrandProducts,
				mvRecords: new Map(),
			});
			jest
				.spyOn(relatedProductsService, 'getBrandProducts')
				.mockResolvedValue({ brand: 'TestBrand', brand_products: null as any, product_id: '', color_id: null, sort_by: null });

			const response = await request(getHttpServer)
				.get('/related-products/brand?brand=TestBrand')
				.expect(200);

			expect(response.body).toHaveProperty('brand', 'TestBrand');
		});

		it('should cover getCurrentColorStyle false branch when style is found by getStyleByStyleId', async () => {
			const mockStyleColorModel = app.get(StyleColorModel);
			const mockFoundStyle: IStyleColorBase = {
				_id: 'found-uuid',
				style_id: 12345,
				color_id: 0,
				color_name: 'Default',
				color_rgb: '#000000',
				is_active: true,
				image_url: null,
				created_at: new Date(),
				updated_at: new Date(),
				deleted_at: null,
			};

			jest.spyOn(cacheService, 'get').mockImplementation(() => Promise.resolve(null));
			jest.spyOn(mockStyleColorModel, 'findByStyleAndColorId').mockResolvedValue(null);
			jest.spyOn(mockStyleColorModel, 'findByStyleId').mockResolvedValue(mockFoundStyle);
			jest
				.spyOn(algoliaService, 'getRelatedProductIds')
				.mockResolvedValue([885600, 885601, 885602, 885603]);
			jest.spyOn(productHydrationService, 'hydrateProductsWithColors').mockResolvedValue({
				products: mockRelatedProductsFromAlgolia,
				mvRecords: new Map(),
			});
			jest
				.spyOn(productHydrationService, 'convertMvColorsToProductColors')
				.mockReturnValue([]);

			const response = await request(getHttpServer)
				.get('/related-products/12345?colorId=99999')
				.expect(200);

			const body = response.body as RelatedProductsResponseDto;

			expect(body).toHaveProperty('product_id', '12345');
			expect(body).toHaveProperty('related_products');
			expect(mockStyleColorModel.findByStyleId).toHaveBeenCalledWith({ styleId: 12345 });
		});

		it('should cover applyColorMatching cache hit when same style_id appears twice', async () => {
			const mockStyleColorModel = app.get(StyleColorModel);
			const mockStyleColor: IStyleColorBase = {
				_id: 'test-uuid',
				style_id: 12345,
				color_id: 885600,
				color_name: 'Red',
				color_rgb: '#FF0000',
				is_active: true,
				image_url: 'https://example.com/red.jpg',
				created_at: new Date(),
				updated_at: new Date(),
				deleted_at: null,
			};

			const twoProductsSameStyleId: IRelatedProduct[] = [
				{ ...mockRelatedProductsFromAlgolia[0]!, style_id: 885600 },
				{ ...mockRelatedProductsFromAlgolia[1]!, style_id: 885600 },
			];

			const mockColors = [
				{
					id: 885600,
					name: 'Red',
					rbgs: [{ R: 255, G: 0, B: 0 }],
					image_url: 'https://example.com/red.jpg',
				},
			];

			const mvRecordsMap = new Map();
			mvRecordsMap.set(885600, { colors: mockColors });

			jest.spyOn(cacheService, 'get').mockImplementation(() => Promise.resolve(null));
			jest.spyOn(mockStyleColorModel, 'findByStyleAndColorId').mockResolvedValue(mockStyleColor);
			jest
				.spyOn(algoliaService, 'getRelatedProductIds')
				.mockResolvedValue([885600, 885600]);
			jest.spyOn(productHydrationService, 'hydrateProductsWithColors').mockResolvedValue({
				products: twoProductsSameStyleId,
				mvRecords: mvRecordsMap,
			});
			jest
				.spyOn(productHydrationService, 'convertMvColorsToProductColors')
				.mockReturnValue(mockColors);
			jest.spyOn(colorMatchWorkerService, 'findClosestColorId').mockResolvedValue(885600);

			const response = await request(getHttpServer)
				.get('/related-products/12345?colorId=885600')
				.expect(200);

