private async applyColorMatching(
	products: IRelatedProduct[],
	mvRecords: Map<number, IStylesMvBase>,
	currentStyleColor: IStyleColorBase,
): Promise<IRelatedProduct[]> {
	const colorCache = new Map<
		number,
		ReturnType<typeof this.productHydrationService.convertMvColorsToProductColors>
	>();

	return Promise.all(
		products.map(async (product) => {
			const mv = mvRecords.get(product.style_id);
			let colors = colorCache.get(product.style_id);
			if (!colors) {
				colors = this.productHydrationService.convertMvColorsToProductColors({
					colors: mv?.colors ?? null,
				});
				colorCache.set(product.style_id, colors);
			}
			if (colors.length > 0) {
				const closestColorId = await this.colorMatchWorkerService.findClosestColorId({
					color: currentStyleColor,
					palette: colors,
				});
				const closestColor = colors.find((c) => c.id === closestColorId);
				if (closestColor) {
					return {
						...product,
						color: closestColorId,
						image_src: closestColor.image_url ?? product.image_src,
					};
				}
			}
			return product;
		}),
	);
}

