@LogExecution({
	logParams: false,
	logResponse: false,
	logExecutionTime: false,
})
async getRelatedProducts({
	productId,
	query,
}: {
	productId: string;
	query: RelatedProductsQueryDto;
}): Promise<RelatedProductsResponseDto> {
	if (!productId || productId.trim() === '') {
		this.logger.error('Product ID is required to fetch related products');
		throw new BadRequestException('Product ID is required');
	}

	const numericProductId = Number(productId);
	if (!Number.isInteger(numericProductId) || numericProductId <= 0) {
		this.logger.error(`Invalid Product ID format: ${productId}`);
		throw new BadRequestException(
			`Product ID must be a valid positive integer, received: ${productId}`,
		);
	}

	const { limit, colorId } = query;

	try {
		const styleIds = await this.algoliaService.getRelatedProductIds({
			productId: numericProductId,
		});
		this.logger.debug('[getRelatedProducts] Algolia returned related IDs', {
			count: styleIds.length,
		});

		if (styleIds.length === 0) {
			throw new NotFoundException(
				`No related products found for product ID: ${productId}`,
			);
		}

		const [currentStyleColor, { products, mvRecords }] = await Promise.all([
			this.getCurrentColorStyle(numericProductId, colorId),
			this.productHydrationService.hydrateProductsWithColors({
				styleIds,
			}),
		]);

		const relatedProducts = currentStyleColor
			? await this.applyColorMatching(products, mvRecords, currentStyleColor)
			: products;
		this.logger.debug('[getRelatedProducts] Hydration complete', {
			hydratedCount: relatedProducts.length,
		});

		if (relatedProducts.length === 0) {
			throw new NotFoundException(
				`No related products found for product ID: ${productId}`,
			);
		}

		return {
			product_id: productId,
			related_products: relatedProducts.slice(0, limit),
			color_id: colorId ?? null,
		};
	} catch (error: unknown) {
		const err = error instanceof Error ? error : new Error(String(error));
		this.logger.error(
			`Error fetching related products from Algolia for productId ${productId}, colorId ${colorId}: ${err.message}`,
			err.stack,
		);

		await this.metricsService.incrementDailyCounter({
			metricType: dailyTrackingKeys.MMS_REQUESTS,
		});

		const [alternativeStyleIds, currentStyleColor] = await Promise.all([
			this.styleAlternativesService.getAlternativeStyleIds({
				styleId: numericProductId,
			}),
			this.getCurrentColorStyle(numericProductId, colorId),
		]);
		this.logger.debug('[getRelatedProducts] DB alternatives fetched', {
			count: alternativeStyleIds.length,
		});

		if (alternativeStyleIds.length === 0) {
			this.logger.warn(`No DB alternatives found for product ID: ${productId}`);
			return {
				product_id: productId,
				related_products: [],
				mms_fallback: true,
				color_id: colorId ?? null,
			};
		}

		const alternatives = await this.productHydrationService.hydrateProducts({
			styleIds: alternativeStyleIds,
			currentStyleColor,
			activeOnly: true,
		});

		this.logger.log('[getRelatedProducts] Fallback completed', {
			productId,
			fallbackCount: Math.min(alternatives.length, limit ?? alternatives.length),
		});

		return {
			product_id: productId,
			related_products: alternatives.slice(0, limit),
			mms_fallback: true,
			color_id: colorId ?? null,
		};
	}
}

async getBrandProducts(
	query: BrandProductsQueryDto,
): Promise<BrandProductsResponseDto> {
	const { brand, limit, colorId, styleId, sortBy } = query;

	this.logger.debug('[getBrandProducts] Starting brand products fetch', {
